# ─── Search helpers ──────────────────────────────────────────────────────────

def haversine_miles(lat1, lon1, lat2, lon2):
    R = 3958.8
    phi1, phi2 = math.radians(lat1), math.radians(lat2)
    dphi = math.radians(lat2 - lat1)
    dlambda = math.radians(lon2 - lon1)
    a = math.sin(dphi/2)**2 + math.cos(phi1)*math.cos(phi2)*math.sin(dlambda/2)**2
    return R * 2 * math.asin(math.sqrt(a))


def search_incidents(airport_code: str = None, radius_mi: float = None, year: int = None):
    results = list(_raw)
    if airport_code:
        code = airport_code.upper()
        if code in AIRPORTS and radius_mi is not None:
            ref = AIRPORTS[code]
            results = [
                r for r in results
                if r.get("lat") is not None and r.get("lon") is not None
                and haversine_miles(ref["lat"], ref["lon"], r["lat"], r["lon"]) <= radius_mi
            ]
        elif code in AIRPORTS:
            results = [r for r in results if r.get("airport_code") == code]
        else:
            results = [r for r in results if r.get("airport_code") == code]
    if year:
        results = [r for r in results if r["date"].year == year]
    return results


def get_by_id(report_id: str):
    for r in _raw:
        if r["report_id"] == report_id:
            # Auto-generate narrative from pilot_description and crew_effects
            parts = []
            if r.get("pilot_description"):
                parts.append(r["pilot_description"])
            if r.get("crew_effects"):
                parts.append(f"Crew effects: {r['crew_effects']}.")
            r["narrative"] = " ".join(parts) if parts else "No narrative available."
            return r
    return None


def get_by_type(incident_type: str):
    return [r for r in _raw if r["incident_type"] == incident_type]


def get_airport_summary(airport_code: str):
    code = airport_code.upper()
    incidents = [r for r in _raw if r.get("airport_code") == code]
    if not incidents:
        return None
    by_type = {}
    for r in incidents:
        by_type[r["incident_type"]] = by_type.get(r["incident_type"], 0) + 1
    most_common = max(by_type, key=lambda k: by_type[k])
    years = [r["date"].year for r in incidents]
    return {
        "airport_code": code,
        "total_incidents": len(incidents),
        "incident_count_by_type": by_type,
        "year_range": (min(years), max(years)),
        "most_common_hazard": most_common,
    }


def count_total():
    return len(_raw)
